import tensorflow as tf

class RMSNorm(tf.keras.layers.Layer):
    def __init__(self, eps=1e-6, **kwargs):
        super().__init__(**kwargs)
        self.eps = eps

    def build(self, input_shape):
        self.gamma = self.add_weight(
            name='gamma', shape=(input_shape[-1],),
            initializer='ones', trainable=True
        )
        super().build(input_shape)

    def call(self, x):
        rms = tf.sqrt(tf.reduce_mean(tf.square(x), axis=-1, keepdims=True) + self.eps)
        return self.gamma * (x / rms)

rms_norm = RMSNorm()
x = tf.random.normal([2, 10, 512])
out = rms_norm(x)
print(f"입력: {x.shape} → 출력: {out.shape}")

import tensorflow as tf

class SwiGLU_FFN(tf.keras.layers.Layer):
    def __init__(self, d_model, d_ff, **kwargs):
        super().__init__(**kwargs)
        self.gate_proj = tf.keras.layers.Dense(d_ff, use_bias=False)
        self.up_proj   = tf.keras.layers.Dense(d_ff, use_bias=False)
        self.down_proj = tf.keras.layers.Dense(d_model, use_bias=False)

    def call(self, x):
        return self.down_proj(tf.nn.silu(self.gate_proj(x)) * self.up_proj(x))

ffn = SwiGLU_FFN(d_model=512, d_ff=1376)
x = tf.random.normal([2, 10, 512])
out = ffn(x)
print(f"입력: {x.shape} → 출력: {out.shape}, 파라미터: {ffn.count_params():,}")
